@app.before_request
def startup():
    init_db()


def now_iso():
    return datetime.now(timezone.utc).isoformat()


def require_login(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        user_id = session.get("user_id")
        if not user_id:
            return jsonify({"error": "Authentication required"}), 401
        db = get_db()
        user = db.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
        if not user:
            session.clear()
            return jsonify({"error": "Invalid session"}), 401
        g.current_user = user
        return f(*args, **kwargs)
    return wrapper


def send_email(to_email, subject, body):
    print("=== EMAIL ===")
    print(f"To: {to_email}")
    print(f"Subject: {subject}")
    print(body)
    print("=============")


def create_reset_token(user):
    token = serializer.dumps(
        {"user_id": user["id"], "email": user["email"]},
        salt=app.config["RESET_TOKEN_SALT"]
    )
    db = get_db()
    expires_at = (datetime.now(timezone.utc) + timedelta(seconds=app.config["RESET_TOKEN_MAX_AGE_SECONDS"])).isoformat()
    db.execute(
        "INSERT INTO mfa_reset_tokens (user_id, token, used, created_at, expires_at) VALUES (?, ?, 0, ?, ?)",
        (user["id"], token, now_iso(), expires_at)
    )
    db.commit()
    return token


def validate_stored_token(token):
    db = get_db()
    row = db.execute(
        "SELECT * FROM mfa_reset_tokens WHERE token = ?",
        (token,)
    ).fetchone()
    if not row:
        return None, "Invalid token"
    if row["used"]:
        return None, "Token already used"
    expires_at = datetime.fromisoformat(row["expires_at"])
    if datetime.now(timezone.utc) > expires_at:
        return None, "Token expired"
    return row, None


@app.route("/register", methods=["POST"])
def register():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    password = data.get("password") or ""

    if not email or not password:
        return jsonify({"error": "Email and password are required"}), 400

    db = get_db()
    existing = db.execute("SELECT id FROM users WHERE email = ?", (email,)).fetchone()
    if existing:
        return jsonify({"error": "User already exists"}), 409

    db.execute(
        "INSERT INTO users (email, password_hash, mfa_enabled, mfa_secret, created_at) VALUES (?, ?, 0, NULL, ?)",
        (email, generate_password_hash(password), now_iso())
    )
    db.commit()
    return jsonify({"message": "User registered"}), 201


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    password = data.get("password") or ""

    if not email or not password:
        return jsonify({"error": "Email and password are required"}), 400

    db = get_db()
    user = db.execute("SELECT * FROM users WHERE email = ?", (email,)).fetchone()
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "Invalid credentials"}), 401

    if user["mfa_enabled"]:
        session.clear()
        session["pending_user_id"] = user["id"]
        return jsonify({
            "message": "MFA required",
            "mfa_required": True
        }), 200

    session.clear()
    session["user_id"] = user["id"]
    return jsonify({
        "message": "Logged in",
        "mfa_required": False
    }), 200


@app.route("/mfa/verify", methods=["POST"])
def verify_mfa():
    data = request.get_json(silent=True) or {}
    code = data.get("code") or ""
    pending_user_id = session.get("pending_user_id")

    if not pending_user_id:
        return jsonify({"error": "No MFA challenge in progress"}), 400

    db = get_db()
    user = db.execute("SELECT * FROM users WHERE id = ?", (pending_user_id,)).fetchone()
    if not user:
        session.clear()
        return jsonify({"error": "Invalid session"}), 401

    if not user["mfa_enabled"]:
        session.clear()
        session["user_id"] = user["id"]
        return jsonify({"message": "Logged in"}), 200

    if code != "123456":
        return jsonify({"error": "Invalid MFA code"}), 401

    session.clear()
    session["user_id"] = user["id"]
    return jsonify({"message": "Logged in with MFA"}), 200


